using UnityEngine;
using System.Collections.Generic;

/// <summary>
/// Escalar (CLM do GDD) — REFORMULADO (P4 + correcção do botão de agarrar):
/// escalar usa o botão de INTERAGIR (não há botão de "agarrar" dedicado).
///
/// - Paredes/cipós verticais (ClimbableSurface.Parede, exige 'canClimb'):
///   SEGURAR Interagir + carregar para CIMA junto à parede agarra-se e
///   sobe/desce. Soltar Interagir larga a parede.
/// - Cordas/Escadas (ClimbableSurface.Corda/Escada, aceitam 'canClimb' OU
///   'canGrab'): basta APERTAR Interagir enquanto estiver dentro da área para
///   agarrar/largar (toggle) — não precisa segurar nem carregar para cima.
/// - Layers "climbableLayer" (legado, sem componente): tratadas como Parede.
/// </summary>
[RequireComponent(typeof(PlayerMotor2D), typeof(Rigidbody2D))]
public class ClimbAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    [Header("Detecção de superfície escalável")]
    [Tooltip("Layers escaláveis SEM componente ClimbableSurface (legado — tratadas como Parede, exigem canClimb).")]
    [SerializeField] private LayerMask climbableLayer;

    [Tooltip("Offset (a partir do transform do player) do centro da caixa de procura.")]
    [SerializeField] private Vector2 checkOffset = Vector2.zero;

    [Tooltip("Tamanho da caixa de procura de superfícies escaláveis (cobre a frente e o corpo do player — apanha cordas/escadas sobrepostas).")]
    [SerializeField] private Vector2 checkSize = new Vector2(1f, 1.2f);

    [Header("Input")]
    [Tooltip("Auto-preenchido.")]
    [SerializeField] private PlayerInputRouter input;

    [Tooltip("Quanto de input para CIMA é preciso para agarrar uma Parede (0..1).")]
    [Range(0.1f, 1f)] public float upInputThreshold = 0.3f;

    private PlayerMotor2D motor;
    private Rigidbody2D rb;

    // Buffer NonAlloc reutilizável — evita alocação por frame em OverlapBox.
    private static readonly Collider2D[] _overlapBuffer = new Collider2D[16];

    private AnimalFormData form;
    private bool enabledForForm;
    private float climbSpeed;
    private float gravityBeforeClimb;

    private bool isClimbing;
    private bool climbingVine; // true se agarrado por toggle (Corda/Escada) — ignora InteractHeld para soltar.
    private float surfaceSpeedMultiplier = 1f;

    /// <summary>true enquanto o player está agarrado a uma superfície escalável.</summary>
    public bool IsClimbing => isClimbing;

    // ---- IAbility (item 8) ----
    // Climb não usa o botão de habilidade (entra/sai via Interagir/Update — ver
    // TryToggleVineAttach e Update acima). Activate/Release ficam sem efeito;
    // o que importa para o cancelamento central é Cancel/IsActive.
    void IAbility.Activate() { }
    void IAbility.Release() { }
    public void Cancel(AbilityCancelReason reason) => StopClimb();
    public float CooldownRemaining => 0f;
    bool IAbility.IsActive => isClimbing;

    // ---- IActiveAbility (Tarefa #34 — HUD) ----
    // Sem cooldown: a HUD não mostra indicador para esta habilidade.
    public float CooldownDuration => 0f;
    public bool CanActivate => enabledForForm;

    /// <summary>AnimalsDebugPanel — sem cooldown próprio (no-op).</summary>
    public void ResetCooldown() { }

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
        rb = GetComponent<Rigidbody2D>();

        if (input == null) input = GetComponent<PlayerInputRouter>();
    }

    public void ConfigureFromForm(AnimalFormData newForm)
    {
        form = newForm;

        // canClimb (paredes/cordas/escadas) OU canGrab (cordas/escadas).
        enabledForForm = form != null && (form.canClimb || form.canGrab);

        if (!enabledForForm)
        {
            StopClimb();
            return;
        }

        climbSpeed = form.climbSpeed > 0f ? form.climbSpeed : 4f;
    }

    /// <summary>
    /// Chamado pelo AbilityRouter ao apertar Interagir (toque, não hold): se o
    /// player estiver dentro de uma Corda/Escada compatível com a forma,
    /// agarra-se (ou larga, se já estiver agarrado a uma). Devolve true se
    /// consumiu o toque (o AbilityRouter não deve tratar mais nada nesse caso).
    /// </summary>
    public bool TryToggleVineAttach()
    {
        if (isClimbing && climbingVine)
        {
            StopClimb();
            return true;
        }

        if (!enabledForForm || isClimbing) return false;

        Vector2 center = (Vector2)transform.position + checkOffset;
        int count = Physics2D.OverlapBoxNonAlloc(center, checkSize, 0f, _overlapBuffer);

        for (int i = 0; i < count; i++)
        {
            var hit = _overlapBuffer[i];
            if (hit == null || hit.gameObject == gameObject) continue;

            var surface = hit.GetComponent<ClimbableSurface>();
            if (surface == null) continue;
            if (surface.kind == ClimbableKind.Parede) continue; // paredes usam hold+cima, não toggle.
            if (surface.kind == ClimbableKind.CipoBalanco) continue; // tratado pelo SwingAbility (balanço), não aqui.
            if (!surface.AllowsForm(form)) continue;

            StartClimb(surface.climbSpeedMultiplier, vine: true);
            return true;
        }

        return false;
    }

    private void Update()
    {
        if (!isClimbing)
        {
            // Início (Parede): Interagir premido + input para cima + parede ao alcance.
            if (!enabledForForm || !form.canClimb) return;
            if (input == null || !input.InteractHeld || motor.MovementLocked) return;

            float upInput = input.Move.y;
            if (upInput < upInputThreshold) return;

            if (TryFindClimbableWall(out float multiplier))
                StartClimb(multiplier, vine: false);

            return;
        }

        // Parede: soltar Interagir larga.
        if (!climbingVine && (input == null || !input.InteractHeld))
        {
            StopClimb();
            return;
        }

        // Já não há superfície (chegou ao topo/fim) -> solta.
        if (!TryFindClimbable(out surfaceSpeedMultiplier))
        {
            StopClimb();
            return;
        }

        float vY = input != null ? input.Move.y : 0f;
        rb.linearVelocity = new Vector2(0f, vY * climbSpeed * surfaceSpeedMultiplier);
    }

    private void StartClimb(float multiplier, bool vine)
    {
        isClimbing = true;
        climbingVine = vine;
        surfaceSpeedMultiplier = multiplier;
        gravityBeforeClimb = rb.gravityScale;

        rb.gravityScale = 0f;
        rb.linearVelocity = Vector2.zero;
        motor.SetMovementLocked(true, this);
    }

    /// <summary>Tarefa #7 — Coala: aplica o bónus de defesa (climbDefenseBonus) enquanto agarrado/a escalar. Chamado por PlayerCombat.TryDamagePlayer.</summary>
    public int ApplyClimbDefense(int damage)
    {
        if (!isClimbing || form == null) return damage;
        return form.ApplyDefense(damage, form.climbDefenseBonus);
    }

    /// <summary>Larga a superfície: restaura a gravidade e devolve o controlo ao motor.</summary>
    public void StopClimb()
    {
        if (!isClimbing) return;

        isClimbing = false;
        climbingVine = false;
        rb.gravityScale = gravityBeforeClimb;
        rb.linearVelocity = Vector2.zero;
        motor.SetMovementLocked(false, this);
    }

    /// <summary>Procura qualquer superfície escalável válida (usado enquanto já está agarrado).</summary>
    private bool TryFindClimbable(out float speedMultiplier)
    {
        speedMultiplier = 1f;

        Vector2 center = (Vector2)transform.position + checkOffset;
        int count = Physics2D.OverlapBoxNonAlloc(center, checkSize, 0f, _overlapBuffer);

        for (int i = 0; i < count; i++)
        {
            var hit = _overlapBuffer[i];
            if (hit == null || hit.gameObject == gameObject) continue;

            var surface = hit.GetComponent<ClimbableSurface>();
            if (surface != null && surface.AllowsForm(form))
            {
                speedMultiplier = surface.climbSpeedMultiplier;
                return true;
            }

            if (form != null && form.canClimb && climbableLayer.value != 0 &&
                (climbableLayer.value & (1 << hit.gameObject.layer)) != 0)
            {
                return true;
            }
        }

        return false;
    }

    /// <summary>Procura apenas Paredes (ClimbableSurface.Parede ou layer legada) — usado para iniciar com hold+cima.</summary>
    private bool TryFindClimbableWall(out float speedMultiplier)
    {
        speedMultiplier = 1f;

        Vector2 center = (Vector2)transform.position + checkOffset;
        int count = Physics2D.OverlapBoxNonAlloc(center, checkSize, 0f, _overlapBuffer);

        for (int i = 0; i < count; i++)
        {
            var hit = _overlapBuffer[i];
            if (hit == null || hit.gameObject == gameObject) continue;

            var surface = hit.GetComponent<ClimbableSurface>();
            if (surface != null)
            {
                if (surface.kind == ClimbableKind.Parede && surface.AllowsForm(form))
                {
                    speedMultiplier = surface.climbSpeedMultiplier;
                    return true;
                }
                continue;
            }

            // Layer legada = Parede (exige canClimb).
            if (climbableLayer.value != 0 && (climbableLayer.value & (1 << hit.gameObject.layer)) != 0)
                return true;
        }

        return false;
    }

    private void OnDrawGizmosSelected()
    {
        Gizmos.color = new Color(0.3f, 1f, 0.3f, 0.5f);
        Gizmos.DrawWireCube((Vector2)transform.position + checkOffset, checkSize);
    }
}
